great.gb_distributer_father_goods_id 'g_gb_distributer_father_goods_id', great.gb_dfg_fathers_father_id 'g_gb_dfg_fathers_father_id', great.gb_dfg_nx_goods_id 'g_gb_dfg_nx_goods_id', great.gb_dfg_father_goods_name 'g_gb_dfg_father_goods_name', great.gb_dfg_father_goods_img 'g_gb_dfg_father_goods_img', great.gb_dfg_father_goods_sort 'g_gb_dfg_father_goods_sort', dfg.gb_distributer_father_goods_id 'f_gb_distributer_father_goods_id', dfg.gb_dfg_fathers_father_id 'f_gb_dfg_fathers_father_id', dfg.gb_dfg_father_goods_name 'f_gb_dfg_father_goods_name', dfg.gb_dfg_father_goods_img 'f_gb_dfg_father_goods_img', dfg.gb_dfg_father_goods_sort 'f_gb_dfg_father_goods_sort'
from gb_department_dis_goods as ddg left join gb_department_goods_stock as gdgs on gdgs.gb_dgs_gb_dep_dis_goods_id = ddg.gb_department_dis_goods_id and gdgs.gb_dgs_rest_weight > 0 and gdgs.gb_dgs_status > -1 and gdgs.gb_dgs_gb_department_id = #{depId} left join gb_distributer_goods as dg on dg.gb_distributer_goods_id = ddg.gb_DDG_dis_goods_id left join gb_distributer_alias as gda on gda.gb_DA_dis_goods_id = dg.gb_distributer_goods_id left join gb_distributer_standard as gdd on gdd.gb_DS_dis_goods_id= dg.gb_distributer_goods_id left join gb_department as gd on gd.gb_department_id = dg.gb_dg_gb_department_id left join gb_distributer_alias as da on da.gb_DA_dis_goods_id = ddg.gb_DDG_dis_goods_id left join gb_distributer_standard as ds on ds.gb_DS_dis_goods_id = dg.gb_distributer_goods_id left join gb_distributer_father_goods as dfg on dfg.gb_distributer_father_goods_id = ddg.gb_DDG_dis_goods_father_id left join gb_distributer_father_goods as great on great.gb_distributer_father_goods_id = dfg.gb_dfg_fathers_father_id left join gb_distributer_father_goods as greatGrand on greatGrand.gb_distributer_father_goods_id = great.gb_dfg_fathers_father_id left join nx_goods as ng on ng.nx_goods_id = great.gb_dfg_nx_goods_id
left join gb_department_orders as dor on dor.gb_DO_dis_goods_id = ddg.gb_DDG_dis_goods_id and dor.gb_DO_status < #{status} and dor.gb_DO_status > -1 and dor.gb_DO_department_id = #{depId} and dor.gb_DO_order_type != 9 left join nx_distributer as nd on nd.nx_distributer_id = ddg.gb_DDG_nx_distributer_id left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = ddg.gb_DDG_nx_distributer_goods_id left join gb_department_goods_stock_reduce as gdgsr on gdgsr.gb_dgsr_gb_goods_stock_id = gdgs.gb_department_goods_stock_id and gdgsr.gb_dgsr_type = 4 and gdgsr.gb_dgsr_status = -1 left join gb_department_goods_daily as gsrd on gsrd.gb_dgd_gb_dep_dis_goods_id = ddg.gb_department_dis_goods_id and gsrd.gb_dgd_date = #{date} and gsrd.gb_dgd_gb_department_id left join nx_jrdh_supplier as njs on njs.nx_jrdh_supplier_id = dg.gb_dg_gb_supplier_id
