and dg.gb_dg_is_self_control = #{isSelf}
and dg.gb_dg_goods_type = #{goodsType}
and dg.gb_dg_control_price = #{price}
and dg.gb_dg_control_fresh = #{fresh}
and dg.gb_dg_gb_supplier_id is not null
order by greatGrand.gb_dfg_father_goods_sort , great.gb_dfg_father_goods_sort , dfg.gb_dfg_father_goods_sort, dg.gb_dg_goods_sort

select * , inventoryStock.gb_department_goods_stock_id 'inventory_gb_department_goods_stock_id', inventoryStock.gb_dgs_gb_dep_dis_goods_id 'inventory_gb_dgs_gb_dep_dis_goods_id', inventoryStock.gb_dgs_weight 'inventory_gb_dgs_weight', inventoryStock.gb_dgs_date 'inventory_gb_dgs_date', inventoryStock.gb_dgs_week 'inventory_gb_dgs_week' from gb_department_dis_goods as ddg left join gb_department_goods_stock as gdgs on gdgs.gb_dgs_gb_dep_dis_goods_id = ddg.gb_department_dis_goods_id and gdgs.gb_dgs_rest_weight > 0 and gdgs.gb_dgs_status > -1 left join gb_distributer_goods as dg on dg.gb_distributer_goods_id = ddg.gb_DDG_dis_goods_id left join gb_department as gd on gd.gb_department_id = dg.gb_dg_gb_department_id left join gb_distributer_alias as da on da.gb_DA_dis_goods_id = ddg.gb_DDG_dis_goods_id left join gb_distributer_standard as ds on ds.gb_DS_dis_goods_id = dg.gb_distributer_goods_id left join gb_distributer_father_goods as dfg on dfg.gb_distributer_father_goods_id = ddg.gb_DDG_dis_goods_father_id left join gb_department_orders as dor on dor.gb_DO_dis_goods_id = ddg.gb_DDG_dis_goods_id and dor.gb_DO_status < #{status} and dor.gb_DO_status > -1 and dor.gb_DO_department_id = #{depId} and dor.gb_DO_order_type != 9 left join nx_distributer as nd on nd.nx_distributer_id = dg.gb_dg_nx_distributer_id left join gb_department_goods_stock as inventoryStock on inventoryStock.gb_dgs_gb_dep_dis_goods_id = ddg.gb_department_dis_goods_id left join gb_department_goods_stock_reduce as gdgsr on gdgsr.gb_dgsr_gb_goods_stock_id = gdgs.gb_department_goods_stock_id and gdgsr.gb_dgsr_type = 4 and gdgsr.gb_dgsr_status = -1 left join gb_department_goods_daily as gsrd on gsrd.gb_dgd_gb_dep_dis_goods_id = ddg.gb_department_dis_goods_id and gsrd.gb_dgd_date = #{date} left join nx_jrdh_supplier as njs on njs.nx_jrdh_supplier_id = dg.gb_dg_gb_supplier_id
and ddg.gb_DDG_department_father_id = #{depFatherId}
and ddg.gb_DDG_dis_goods_father_id = #{fatherId}
and dg.gb_dg_control_price = #{price}
and dg.gb_dg_control_fresh = #{fresh}
