select * from gb_department_dis_goods as ddg left join gb_department_goods_stock as gdgs on gdgs.gb_dgs_gb_dep_dis_goods_id = ddg.gb_department_dis_goods_id and gdgs.gb_dgs_rest_weight > 0 and gdgs.gb_dgs_status > -1 left join gb_distributer_goods as dg on dg.gb_distributer_goods_id = ddg.gb_DDG_dis_goods_id left join gb_distributer_standard as gds on gds.gb_DS_dis_goods_id = dg.gb_distributer_goods_id left join gb_distributer_alias as da on da.gb_DA_dis_goods_id = dg.gb_distributer_goods_id left join gb_department_orders as dor on dor.gb_DO_dis_goods_id = dg.gb_distributer_goods_id and dor.gb_DO_status < 2 and dor.gb_DO_status > -1 and dor.gb_DO_department_id = #{depId} left join gb_department_user as du on du.gb_department_user_id = dor.gb_DO_order_user_id left join nx_distributer as nd on nd.nx_distributer_id = dg.gb_dg_nx_distributer_id left join gb_department as gd on gd.gb_department_id = ddg.gb_DDG_gb_department_id left join gb_department_goods_daily as gsrd on gsrd.gb_dgd_gb_dep_dis_goods_id = ddg.gb_department_dis_goods_id and gsrd.gb_dgd_date = #{date}
