left join gb_department_orders as dor on dor.gb_DO_dis_goods_id = ddg.gb_DDG_dis_goods_id and dor.gb_DO_status < #{status} and dor.gb_DO_status > -1 and dor.gb_DO_department_id = #{depId} and dor.gb_DO_order_type != 9 left join nx_distributer as nd on nd.nx_distributer_id = ddg.gb_DDG_nx_distributer_id left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = ddg.gb_DDG_nx_distributer_goods_id left join gb_department_goods_stock_reduce as gdgsr on gdgsr.gb_dgsr_gb_goods_stock_id = gdgs.gb_department_goods_stock_id and gdgsr.gb_dgsr_type = 4 and gdgsr.gb_dgsr_status = -1 left join gb_department_goods_daily as gsrd on gsrd.gb_dgd_gb_dep_dis_goods_id = ddg.gb_department_dis_goods_id and gsrd.gb_dgd_date = #{date} and gsrd.gb_dgd_gb_department_id left join nx_jrdh_supplier as njs on njs.nx_jrdh_supplier_id = dg.gb_dg_gb_supplier_id
