LEFT JOIN gb_department_goods_stock_reduce AS gdgsr ON gdgsr.gb_dgsr_gb_goods_stock_id = gdgs.gb_department_goods_stock_id AND gdgsr.gb_dgsr_type = 4 AND gdgsr.gb_dgsr_status = -1
LEFT JOIN gb_department_goods_daily AS gsrd ON gsrd.gb_dgd_gb_dep_dis_goods_id = ddg.gb_department_dis_goods_id AND gsrd.gb_dgd_date = #{date} AND gsrd.gb_dgd_gb_department_id = #{depId}
