and dg.gb_dg_pull_off = #{pull}
and dg.gb_dg_is_franchise_price = #{isPrice}
and dg.gb_dg_is_self_control = #{isSelf}
and greatGrand.gb_distributer_father_goods_id = #{greatGrandId}
GROUP BY dg.gb_distributer_goods_id ORDER BY sort_gg, sort_g, sort_f, sort_dg LIMIT #{limit} OFFSET #{offset} ) AS base INNER JOIN gb_department_dis_goods AS ddg ON ddg.gb_department_dis_goods_id = base.gb_department_dis_goods_id LEFT JOIN gb_distributer_goods AS dg ON dg.gb_distributer_goods_id = ddg.gb_DDG_dis_goods_id LEFT JOIN gb_distributer_father_goods AS dfg ON dfg.gb_distributer_father_goods_id = ddg.gb_DDG_dis_goods_father_id LEFT JOIN gb_distributer_father_goods AS great ON great.gb_distributer_father_goods_id = dfg.gb_dfg_fathers_father_id LEFT JOIN gb_distributer_father_goods AS greatGrand ON greatGrand.gb_distributer_father_goods_id = great.gb_dfg_fathers_father_id
ORDER BY base.sort_gg, base.sort_g, base.sort_f, base.sort_dg

