SELECT ddg.gb_DDG_dis_goods_id,
gg.gb_dfg_father_goods_sort AS sort_gg,
g.gb_dfg_father_goods_sort AS sort_g,
f.gb_dfg_father_goods_sort AS sort_f,
dg.gb_dg_goods_sort AS sort_dg
