LEFT JOIN gb_distributer_goods AS dg ON dg.gb_distributer_goods_id = ddg.gb_DDG_dis_goods_id
LEFT JOIN gb_distributer_father_goods AS f ON f.gb_distributer_father_goods_id = dg.gb_dg_dfg_goods_father_id
LEFT JOIN gb_distributer_father_goods AS g ON g.gb_distributer_father_goods_id = f.gb_dfg_fathers_father_id
LEFT JOIN gb_distributer_father_goods AS gg ON gg.gb_distributer_father_goods_id = g.gb_dfg_fathers_father_id


